import{_ as a,o,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Create & Manage Kingdoms","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/manage-kingdoms.md","filePath":"how-to/manage-kingdoms.md"}'),i={name:"how-to/manage-kingdoms.md"};function r(l,e,s,d,c,g){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="create-manage-kingdoms" tabindex="-1">Create &amp; Manage Kingdoms <a class="header-anchor" href="#create-manage-kingdoms" aria-label="Permalink to &quot;Create &amp; Manage Kingdoms&quot;">​</a></h1><p>The <strong>Kingdoms</strong> area is the top-level management space for a server. It is where a <code>Supreme Admin</code> creates kingdoms and where a <code>Supreme Admin</code> or <code>King</code> reviews the kingdom&#39;s alliances, players, responsible users, recent imports, recent reports, and usage state.</p><blockquote><p>Screenshot placeholder: kingdoms-list.png</p></blockquote><blockquote><p>Screenshot placeholder: kingdom-detail.png</p></blockquote><h2 id="who-can-do-what" tabindex="-1">Who can do what <a class="header-anchor" href="#who-can-do-what" aria-label="Permalink to &quot;Who can do what&quot;">​</a></h2><ul><li><code>Supreme Admin</code> can create a new kingdom.</li><li><code>Supreme Admin</code> and <code>King</code> can open a kingdom they are allowed to manage.</li><li>Kingdom work usually continues inside the kingdom detail page after creation.</li></ul><h2 id="create-a-kingdom" tabindex="-1">Create a kingdom <a class="header-anchor" href="#create-a-kingdom" aria-label="Permalink to &quot;Create a kingdom&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>In the <strong>Kingdoms</strong> section, enter <strong>Kingdom name</strong> and <strong>Server code</strong>.</li><li>Select <strong>Add</strong>.</li></ol><p>After that, open the kingdom from the list to manage it in more detail.</p><h2 id="what-you-can-do-on-the-kingdom-page" tabindex="-1">What you can do on the kingdom page <a class="header-anchor" href="#what-you-can-do-on-the-kingdom-page" aria-label="Permalink to &quot;What you can do on the kingdom page&quot;">​</a></h2><p>The kingdom detail page gives you one place to:</p><ul><li>rename the kingdom</li><li>review player and alliance counts</li><li>open the <strong>Recycle Bin</strong></li><li>add new alliances</li><li>review responsible users</li><li>spot recent imports and reports</li></ul><h2 id="read-the-page-from-top-to-bottom" tabindex="-1">Read the page from top to bottom <a class="header-anchor" href="#read-the-page-from-top-to-bottom" aria-label="Permalink to &quot;Read the page from top to bottom&quot;">​</a></h2><p>The main sections are usually:</p><ul><li>a hero area with quick actions</li><li>summary cards for players, alliances, active players, and API-linked players</li><li>a usage panel</li><li><strong>Kingdom Information</strong></li><li><strong>Alliances</strong></li><li><strong>Add Alliance</strong></li><li><strong>Responsible Users</strong></li><li><strong>Players</strong></li><li><strong>Recent Imports</strong></li><li><strong>Recent Reports</strong></li></ul><h2 id="subscription-note-for-kingdom-pages" tabindex="-1">Subscription note for kingdom pages <a class="header-anchor" href="#subscription-note-for-kingdom-pages" aria-label="Permalink to &quot;Subscription note for kingdom pages&quot;">​</a></h2><p>You may see usage and premium-related information here. Keep these two rules in mind:</p><ul><li>A kingdom plan does not automatically give paid status to every alliance under it.</li><li>Alliance grant limits are controlled by the kingdom&#39;s current plan, so those limits can change over time.</li></ul><p>This guide only points out where you will see those signals. A later subscriptions section covers the rules in detail.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Create the kingdom first, then add alliances under it.</li><li>Use the kingdom page as the overview for server-wide cleanup and ownership checks.</li><li>Open user management from here when the kingdom has no responsible users yet.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manage-alliances.html">Create &amp; Manage Alliances</a></li><li><a href="./recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./assign-roles.html">Assign or Remove Roles</a></li></ul>',23)])])}const p=a(i,[["render",r]]);export{h as __pageData,p as default};
